use serde::{Deserialize, Serialize};
use std::f64::consts::PI;

// REALCOMPARE implementation from reference
const LT: &str = "LT";
const EQ: &str = "EQ";
const GT: &str = "GT";

fn realcompare(a: f64, b: f64) -> &'static str {
    let scale = a.abs().max(b.abs());
    if scale == 0.0 {
        return "EQ";
    }
    let eps = 0.5e-5 * scale;
    let diff = a - b;
    if diff > eps {
        "GT"
    } else if diff < -eps {
        "LT"
    } else {
        "EQ"
    }
}

// Input structures
#[derive(Deserialize)]
struct Parameters {
    #[serde(rename = "LENGTH1")]
    length1: f64,
    #[serde(rename = "RADIUS1")]
    radius1: f64,
    #[serde(rename = "EPSILON")]
    epsilon: f64,
    #[serde(rename = "AREA1")]
    area1: f64,
    #[serde(rename = "Q_PTS")]
    q_pts: usize,
    #[serde(rename = "QUADS")]
    quads: usize,
    #[serde(rename = "DIST")]
    dist: f64,
    #[serde(rename = "N_PTS")]
    n_pts: usize,
    #[serde(rename = "K_PTS")]
    k_pts: usize,
    #[serde(rename = "A_PTS")]
    a_pts: usize,
    #[serde(rename = "B_PTS")]
    b_pts: usize,
    #[serde(rename = "C_PTS")]
    c_pts: usize,
    #[serde(rename = "D_PTS")]
    d_pts: usize,
    #[serde(rename = "E_PTS")]
    e_pts: usize,
    #[serde(rename = "F_PTS")]
    f_pts: usize,
    #[serde(rename = "G_PTS")]
    g_pts: usize,
    #[serde(rename = "LENGTH2")]
    length2: f64,
    #[serde(rename = "RADIUS2")]
    radius2: f64,
    #[serde(rename = "AREA2")]
    area2: f64,
}

#[derive(Deserialize)]
enum Connector {
    NOTUSED,
    ORR,
    ANDD,
}

#[derive(Deserialize)]
struct Input {
    numpoints: usize,
    x: Vec<f64>,
    y: Vec<f64>,
    parameters: Parameters,
    lcm: Vec<Vec<Connector>>,
    pum_diag: Vec<bool>,
}

// Output structures
#[derive(Serialize)]
struct Output {
    cmv: Vec<bool>,
    pum: Vec<Vec<bool>>,
    fuv: Vec<bool>,
    launch: bool,
}

// Helper functions
fn distance(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x2 - x1).powi(2) + (y2 - y1).powi(2)).sqrt()
}

fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    0.5 * ((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)).abs())
}

// Check if three points can be contained in a circle of given radius
fn fits_in_circle(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64, radius: f64) -> bool {
    // Check if any two points are the same
    if (x1 == x2 && y1 == y2) || (x2 == x3 && y2 == y3) || (x1 == x3 && y1 == y3) {
        // If points coincide, check if all fit in circle from any point
        let d12 = distance(x1, y1, x2, y2);
        let d23 = distance(x2, y2, x3, y3);
        let d13 = distance(x1, y1, x3, y3);
        let max_dist = d12.max(d23).max(d13);
        return realcompare(max_dist, 2.0 * radius) != GT;
    }

    // Check if points are collinear or form a triangle
    let area = triangle_area(x1, y1, x2, y2, x3, y3);

    if area == 0.0 {
        // Collinear points - check if max distance between any two <= diameter
        let d12 = distance(x1, y1, x2, y2);
        let d23 = distance(x2, y2, x3, y3);
        let d13 = distance(x1, y1, x3, y3);
        let max_dist = d12.max(d23).max(d13);
        return realcompare(max_dist, 2.0 * radius) != GT;
    }

    // For a proper triangle, compute circumradius
    let a = distance(x2, y2, x3, y3);
    let b = distance(x1, y1, x3, y3);
    let c = distance(x1, y1, x2, y2);
    let circumradius = (a * b * c) / (4.0 * area);

    realcompare(circumradius, radius) != GT
}

// Calculate angle at vertex (x2, y2) formed by points (x1, y1) and (x3, y3)
fn calculate_angle(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> Option<f64> {
    // Check if vertex coincides with either endpoint
    if (x1 == x2 && y1 == y2) || (x3 == x2 && y3 == y2) {
        return None;
    }

    let dx1 = x1 - x2;
    let dy1 = y1 - y2;
    let dx3 = x3 - x2;
    let dy3 = y3 - y2;

    let dot = dx1 * dx3 + dy1 * dy3;
    let mag1 = (dx1 * dx1 + dy1 * dy1).sqrt();
    let mag3 = (dx3 * dx3 + dy3 * dy3).sqrt();

    if mag1 == 0.0 || mag3 == 0.0 {
        return None;
    }

    let cos_angle = dot / (mag1 * mag3);
    let cos_angle = cos_angle.max(-1.0).min(1.0); // Clamp to [-1, 1]
    Some(cos_angle.acos())
}

// Determine quadrant of a point
fn get_quadrant(x: f64, y: f64) -> usize {
    if realcompare(x, 0.0) != LT {
        if realcompare(y, 0.0) != LT {
            1 // Quadrant I
        } else {
            4 // Quadrant IV
        }
    } else {
        if realcompare(y, 0.0) != LT {
            2 // Quadrant II
        } else {
            3 // Quadrant III
        }
    }
}

// Distance from point to line segment
fn distance_to_line(px: f64, py: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    if x1 == x2 && y1 == y2 {
        // First and last points are identical
        return distance(px, py, x1, y1);
    }

    let dx = x2 - x1;
    let dy = y2 - y1;
    let num = (dy * px - dx * py + x2 * y1 - y2 * x1).abs();
    let den = (dx * dx + dy * dy).sqrt();
    num / den
}

// LIC implementations
fn lic1(x: &[f64], y: &[f64], numpoints: usize, params: &Parameters) -> bool {
    for i in 0..numpoints - 1 {
        let dist = distance(x[i], y[i], x[i + 1], y[i + 1]);
        if realcompare(dist, params.length1) == GT {
            return true;
        }
    }
    false
}

fn lic2(x: &[f64], y: &[f64], numpoints: usize, params: &Parameters) -> bool {
    if numpoints < 3 {
        return false;
    }
    for i in 0..numpoints - 2 {
        if !fits_in_circle(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2], params.radius1) {
            return true;
        }
    }
    false
}

fn lic3(x: &[f64], y: &[f64], numpoints: usize, params: &Parameters) -> bool {
    if numpoints < 3 {
        return false;
    }
    for i in 0..numpoints - 2 {
        if let Some(angle) = calculate_angle(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]) {
            if realcompare(angle, PI - params.epsilon) == LT
                || realcompare(angle, PI + params.epsilon) == GT {
                return true;
            }
        }
    }
    false
}

fn lic4(x: &[f64], y: &[f64], numpoints: usize, params: &Parameters) -> bool {
    if numpoints < 3 {
        return false;
    }
    for i in 0..numpoints - 2 {
        let area = triangle_area(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]);
        if realcompare(area, params.area1) == GT {
            return true;
        }
    }
    false
}

fn lic5(x: &[f64], y: &[f64], numpoints: usize, params: &Parameters) -> bool {
    if numpoints < params.q_pts {
        return false;
    }
    for i in 0..=numpoints - params.q_pts {
        let mut quadrants = vec![false; 5]; // quadrants 1-4
        for j in 0..params.q_pts {
            let quad = get_quadrant(x[i + j], y[i + j]);
            quadrants[quad] = true;
        }
        let count = quadrants.iter().filter(|&&q| q).count();
        if count > params.quads {
            return true;
        }
    }
    false
}

fn lic6(x: &[f64], _y: &[f64], numpoints: usize, _params: &Parameters) -> bool {
    for i in 0..numpoints - 1 {
        if realcompare(x[i + 1], x[i]) == LT {
            return true;
        }
    }
    false
}

fn lic7(x: &[f64], y: &[f64], numpoints: usize, params: &Parameters) -> bool {
    if numpoints < 3 {
        return false;
    }
    if numpoints < params.n_pts {
        return false;
    }

    for i in 0..=numpoints - params.n_pts {
        let first_idx = i;
        let last_idx = i + params.n_pts - 1;

        for j in (first_idx + 1)..last_idx {
            let dist = distance_to_line(
                x[j], y[j],
                x[first_idx], y[first_idx],
                x[last_idx], y[last_idx]
            );
            if realcompare(dist, params.dist) == GT {
                return true;
            }
        }
    }
    false
}

fn lic8(x: &[f64], y: &[f64], numpoints: usize, params: &Parameters) -> bool {
    if numpoints < 3 {
        return false;
    }
    let gap = params.k_pts;
    for i in 0..numpoints {
        let j = i + gap + 1;
        if j < numpoints {
            let dist = distance(x[i], y[i], x[j], y[j]);
            if realcompare(dist, params.length1) == GT {
                return true;
            }
        }
    }
    false
}

fn lic9(x: &[f64], y: &[f64], numpoints: usize, params: &Parameters) -> bool {
    if numpoints < 5 {
        return false;
    }
    for i in 0..numpoints {
        let j = i + params.a_pts + 1;
        let k = j + params.b_pts + 1;
        if k < numpoints {
            if !fits_in_circle(x[i], y[i], x[j], y[j], x[k], y[k], params.radius1) {
                return true;
            }
        }
    }
    false
}

fn lic10(x: &[f64], y: &[f64], numpoints: usize, params: &Parameters) -> bool {
    if numpoints < 5 {
        return false;
    }
    for i in 0..numpoints {
        let j = i + params.c_pts + 1;
        let k = j + params.d_pts + 1;
        if k < numpoints {
            if let Some(angle) = calculate_angle(x[i], y[i], x[j], y[j], x[k], y[k]) {
                if realcompare(angle, PI - params.epsilon) == LT
                    || realcompare(angle, PI + params.epsilon) == GT {
                    return true;
                }
            }
        }
    }
    false
}

fn lic11(x: &[f64], y: &[f64], numpoints: usize, params: &Parameters) -> bool {
    if numpoints < 5 {
        return false;
    }
    for i in 0..numpoints {
        let j = i + params.e_pts + 1;
        let k = j + params.f_pts + 1;
        if k < numpoints {
            let area = triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]);
            if realcompare(area, params.area1) == GT {
                return true;
            }
        }
    }
    false
}

fn lic12(x: &[f64], _y: &[f64], numpoints: usize, params: &Parameters) -> bool {
    if numpoints < 3 {
        return false;
    }
    for i in 0..numpoints {
        let j = i + params.g_pts + 1;
        if j < numpoints {
            if realcompare(x[j], x[i]) == LT {
                return true;
            }
        }
    }
    false
}

fn lic13(x: &[f64], y: &[f64], numpoints: usize, params: &Parameters) -> bool {
    if numpoints < 3 {
        return false;
    }

    let mut found_gt_length1 = false;
    let mut found_lt_length2 = false;

    for i in 0..numpoints {
        let j = i + params.k_pts + 1;
        if j < numpoints {
            let dist = distance(x[i], y[i], x[j], y[j]);
            if realcompare(dist, params.length1) == GT {
                found_gt_length1 = true;
            }
            if realcompare(dist, params.length2) == LT {
                found_lt_length2 = true;
            }
        }
    }

    found_gt_length1 && found_lt_length2
}

fn lic14(x: &[f64], y: &[f64], numpoints: usize, params: &Parameters) -> bool {
    if numpoints < 5 {
        return false;
    }

    let mut found_outside_r1 = false;
    let mut found_inside_r2 = false;

    for i in 0..numpoints {
        let j = i + params.a_pts + 1;
        let k = j + params.b_pts + 1;
        if k < numpoints {
            let fits_r1 = fits_in_circle(x[i], y[i], x[j], y[j], x[k], y[k], params.radius1);
            let fits_r2 = fits_in_circle(x[i], y[i], x[j], y[j], x[k], y[k], params.radius2);

            if !fits_r1 {
                found_outside_r1 = true;
            }
            if fits_r2 {
                found_inside_r2 = true;
            }
        }
    }

    found_outside_r1 && found_inside_r2
}

fn lic15(x: &[f64], y: &[f64], numpoints: usize, params: &Parameters) -> bool {
    if numpoints < 5 {
        return false;
    }

    let mut found_gt_area1 = false;
    let mut found_lt_area2 = false;

    for i in 0..numpoints {
        let j = i + params.e_pts + 1;
        let k = j + params.f_pts + 1;
        if k < numpoints {
            let area = triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]);
            if realcompare(area, params.area1) == GT {
                found_gt_area1 = true;
            }
            if realcompare(area, params.area2) == LT {
                found_lt_area2 = true;
            }
        }
    }

    found_gt_area1 && found_lt_area2
}

// Main DECIDE function
pub fn decide(input: Input) -> Output {
    let numpoints = input.numpoints;
    let x = &input.x;
    let y = &input.y;
    let params = &input.parameters;

    // Calculate CMV
    let mut cmv = vec![false; 15];
    cmv[0] = lic1(x, y, numpoints, params);
    cmv[1] = lic2(x, y, numpoints, params);
    cmv[2] = lic3(x, y, numpoints, params);
    cmv[3] = lic4(x, y, numpoints, params);
    cmv[4] = lic5(x, y, numpoints, params);
    cmv[5] = lic6(x, y, numpoints, params);
    cmv[6] = lic7(x, y, numpoints, params);
    cmv[7] = lic8(x, y, numpoints, params);
    cmv[8] = lic9(x, y, numpoints, params);
    cmv[9] = lic10(x, y, numpoints, params);
    cmv[10] = lic11(x, y, numpoints, params);
    cmv[11] = lic12(x, y, numpoints, params);
    cmv[12] = lic13(x, y, numpoints, params);
    cmv[13] = lic14(x, y, numpoints, params);
    cmv[14] = lic15(x, y, numpoints, params);

    // Calculate PUM
    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = input.pum_diag[i];
            } else {
                pum[i][j] = match input.lcm[i][j] {
                    Connector::NOTUSED => true,
                    Connector::ANDD => cmv[i] && cmv[j],
                    Connector::ORR => cmv[i] || cmv[j],
                };
            }
        }
    }

    // Calculate FUV
    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            fuv[i] = pum[i].iter().all(|&val| val);
        }
    }

    // Calculate LAUNCH
    let launch = fuv.iter().all(|&val| val);

    Output { cmv, pum, fuv, launch }
}

fn main() {
    let input: Input = serde_json::from_reader(std::io::stdin())
        .expect("Failed to parse input JSON");
    let output = decide(input);
    println!("{}", serde_json::to_string(&output).expect("Failed to serialize output"));
}
